using System.ComponentModel;
using Microsoft.Extensions.AI;
using OpenAI;

// ── configuration ───────────────────────────────────────────────────────────
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? "";
var model  = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

if (string.IsNullOrWhiteSpace(apiKey))
{
    Console.Error.WriteLine("Set the OPENAI_API_KEY environment variable to run the agent.");
    return 1;
}

var topic = args.Length > 0
    ? string.Join(' ', args)
    : PromptForTopic();

Console.WriteLine($"\n🔬 Research Agent — topic: \"{topic}\"\n");

// ── tools ───────────────────────────────────────────────────────────────────
var notebook = new Notebook();
var searchTool = new WebSearchTool();

var tools = new AIFunction[]
{
    AIFunctionFactory.Create(searchTool.Search),
    AIFunctionFactory.Create(notebook.AddNote),
    AIFunctionFactory.Create(notebook.GetNotes),
};

// ── chat client with automatic tool invocation ──────────────────────────────
IChatClient client = new OpenAIClient(apiKey)
    .GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

var chatOptions = new ChatOptions { Tools = [.. tools] };

var systemPrompt = $"""
    You are a research assistant. Your job is to thoroughly research the following
    topic by searching the web, recording important findings as notes, and finally
    producing a well-structured summary.

    ## Workflow
    1. Break the topic into 2-4 search queries that cover different angles.
    2. For each query, call the web_search tool to find information.
    3. After each search, call add_note to record the key facts you found.
    4. After finishing all searches, call get_notes to review everything you collected.
    5. Produce a final markdown summary with sections, bullet points, and source URLs.

    Topic: {topic}
    """;

var messages = new List<ChatMessage>
{
    new(ChatRole.System, systemPrompt),
    new(ChatRole.User, $"Please research this topic thoroughly: {topic}")
};

// ── agent loop ──────────────────────────────────────────────────────────────
Console.WriteLine("Researching… (the agent will call tools automatically)\n");

var response = await client.GetResponseAsync(messages, chatOptions);

Console.WriteLine("═══════════════════  RESEARCH SUMMARY  ═══════════════════\n");
Console.WriteLine(response.Text);
Console.WriteLine("\n══════════════════════════════════════════════════════════");
Console.WriteLine($"\n📝 {notebook.Count} note(s) were recorded during research.");

return 0;

// ── helpers ─────────────────────────────────────────────────────────────────
static string PromptForTopic()
{
    Console.Write("Enter a research topic: ");
    var input = Console.ReadLine()?.Trim();
    if (string.IsNullOrWhiteSpace(input))
    {
        Console.Error.WriteLine("No topic provided.");
        Environment.Exit(1);
    }
    return input;
}

// ═══════════════════════════════════════════════════════════════════════════
//  Tool implementations
// ═══════════════════════════════════════════════════════════════════════════

/// <summary>Searches the web and returns relevant snippets.</summary>
sealed class WebSearchTool
{
    private static readonly HttpClient Http = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" },
            { "Accept", "text/html" }
        },
        Timeout = TimeSpan.FromSeconds(15)
    };

    [Description("Search the web for information on a query. Returns relevant text snippets and URLs.")]
    public async Task<string> Search(
        [Description("The search query string")] string query)
    {
        Console.WriteLine($"  🔍 Searching: \"{query}\"");

        try
        {
            // Use DuckDuckGo instant-answer API (no key required)
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
            var json = await Http.GetStringAsync(url);

            var doc = System.Text.Json.JsonDocument.Parse(json);
            var root = doc.RootElement;

            var results = new List<string>();

            // Abstract / instant answer
            var abstractText = root.GetProperty("Abstract").GetString();
            var abstractUrl  = root.GetProperty("AbstractURL").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
                results.Add($"[Abstract] {abstractText}\nSource: {abstractUrl}");

            // Related topics
            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var item in topics.EnumerateArray().Take(5))
                {
                    var text = item.TryGetProperty("Text", out var t) ? t.GetString() : null;
                    var link = item.TryGetProperty("FirstURL", out var u) ? u.GetString() : null;
                    if (!string.IsNullOrWhiteSpace(text))
                        results.Add($"• {text}\n  URL: {link}");
                }
            }

            if (results.Count == 0)
                return $"No instant results found for \"{query}\". Try a more specific query.";

            return string.Join("\n\n", results);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }
}

/// <summary>A simple notebook that stores research notes.</summary>
sealed class Notebook
{
    private readonly List<(DateTime Timestamp, string Category, string Content)> _notes = [];

    public int Count => _notes.Count;

    [Description("Save a research note. Use this to record key findings from searches.")]
    public string AddNote(
        [Description("A short category label (e.g. 'definition', 'history', 'statistics')")] string category,
        [Description("The note content — key facts, quotes, or data points")] string content)
    {
        _notes.Add((DateTime.UtcNow, category, content));
        Console.WriteLine($"  📝 Note added [{category}]: {Truncate(content, 80)}");
        return $"Note #{_notes.Count} saved under '{category}'.";
    }

    [Description("Retrieve all saved research notes so far.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes recorded yet.";

        return string.Join("\n\n", _notes.Select((n, i) =>
            $"Note #{i + 1} [{n.Category}]:\n{n.Content}"));
    }

    private static string Truncate(string s, int max) =>
        s.Length <= max ? s : s[..(max - 1)] + "…";
}

